import * as React from "react"
import { Dialog as DialogPrimitive } from "@base-ui/react/dialog"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui-brutal/button"
import { XIcon } from "lucide-react"

const surfaceVariants = cva(
  "border-2 border-outline shadow-[7px_7px_var(--outline)]",
  {
    variants: {
      hue: {
        none: "bg-popover",
        white: "bg-brutal-surface text-brutal-surface-foreground",
        lightblue: "bg-blue_chill-300 dark:bg-blue_chill-700",
        blue: "bg-blue_chill-500 dark:bg-blue_chill-900",
        aqua: "bg-aqua_green-600 dark:bg-aqua_green-900",
        greenish: "bg-evergreen-300 dark:bg-evergreen-700",
        pollen: "bg-gold-300 dark:bg-gold-700",
        yellow: "bg-gold-500 dark:bg-gold-800",
        apricot: "bg-apricot-400 dark:bg-apricot-700",
        orange: "bg-apricot-500 dark:bg-apricot-800",
        rust: "bg-rust-500 dark:bg-rust-800",
        blush: "bg-cotton_candy-300 dark:bg-cotton_candy-700",
        pink: "bg-cotton_candy-400 dark:bg-cotton_candy-800",
        periwinkle: "bg-periwinkle-400 dark:bg-periwinkle-800",
      },
    },
    defaultVariants: {
      hue: "none",
    },
  }
)

function Dialog({ ...props }: DialogPrimitive.Root.Props) {
  return <DialogPrimitive.Root data-slot="dialog" {...props} />
}

function DialogTrigger({
  asChild,
  children,
  ...props
}: DialogPrimitive.Trigger.Props & { asChild?: boolean }) {
  return (
    <DialogPrimitive.Trigger
      data-slot="dialog-trigger"
      render={asChild && React.isValidElement(children) ? children : undefined}
      {...props}
    >
      {asChild ? undefined : children}
    </DialogPrimitive.Trigger>
  )
}

function DialogPortal({ ...props }: DialogPrimitive.Portal.Props) {
  return <DialogPrimitive.Portal data-slot="dialog-portal" {...props} />
}

function DialogClose({
  asChild,
  children,
  ...props
}: DialogPrimitive.Close.Props & { asChild?: boolean }) {
  return (
    <DialogPrimitive.Close
      data-slot="dialog-close"
      render={asChild && React.isValidElement(children) ? children : undefined}
      {...props}
    >
      {asChild ? undefined : children}
    </DialogPrimitive.Close>
  )
}

function DialogOverlay({
  className,
  ...props
}: DialogPrimitive.Backdrop.Props) {
  return (
    <DialogPrimitive.Backdrop
      data-slot="dialog-overlay"
      className={cn(
        "fixed inset-0 isolate z-50 bg-foreground/10 duration-100 supports-backdrop-filter:backdrop-blur-xs data-open:animate-in data-open:fade-in-0 data-closed:animate-out data-closed:fade-out-0",
        className
      )}
      {...props}
    />
  )
}

function DialogContent({
  className,
  children,
  hue,
  showCloseButton = true,
  ...props
}: DialogPrimitive.Popup.Props & {
  showCloseButton?: boolean
} & VariantProps<typeof surfaceVariants>) {
  return (
    <DialogPortal>
      <DialogOverlay />
      <DialogPrimitive.Popup
        data-slot="dialog-content"
        className={cn(
          "fixed top-1/2 left-1/2 z-50 grid w-full max-w-[calc(100%-2rem)] -translate-x-1/2 -translate-y-1/2 gap-4 rounded-md p-4 text-sm text-popover-foreground duration-100 outline-none sm:max-w-sm data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95",
          surfaceVariants({ hue }),
          className
        )}
        {...props}
      >
        {children}
        {showCloseButton && (
          <DialogPrimitive.Close
            data-slot="dialog-close"
            render={
              <Button
                variant="ghost"
                className="absolute top-2 right-2"
                size="icon-sm"
              />
            }
          >
            <XIcon
            />
            <span className="sr-only">Close</span>
          </DialogPrimitive.Close>
        )}
      </DialogPrimitive.Popup>
    </DialogPortal>
  )
}

function DialogHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="dialog-header"
      className={cn("flex flex-col gap-2", className)}
      {...props}
    />
  )
}

function DialogFooter({
  className,
  showCloseButton = false,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  showCloseButton?: boolean
}) {
  return (
    <div
      data-slot="dialog-footer"
      className={cn(
        "flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2",
        className
      )}
      {...props}
    >
      {children}
      {showCloseButton && (
        <DialogPrimitive.Close render={<Button variant="outline" />}>
          Close
        </DialogPrimitive.Close>
      )}
    </div>
  )
}

function DialogTitle({ className, ...props }: DialogPrimitive.Title.Props) {
  return (
    <DialogPrimitive.Title
      data-slot="dialog-title"
      className={cn(
        "font-heading text-base leading-none font-medium",
        className
      )}
      {...props}
    />
  )
}

function DialogDescription({
  className,
  ...props
}: DialogPrimitive.Description.Props) {
  return (
    <DialogPrimitive.Description
      data-slot="dialog-description"
      className={cn(
        "text-sm text-muted-foreground *:[a]:underline *:[a]:underline-offset-3 *:[a]:hover:text-foreground",
        className
      )}
      {...props}
    />
  )
}

export {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogOverlay,
  DialogPortal,
  DialogTitle,
  DialogTrigger,
}
export type DialogHue = NonNullable<VariantProps<typeof surfaceVariants>["hue"]>

import * as React from "react"
import { Button as ButtonPrimitive } from "@base-ui/react/button"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-sm text-sm font-medium ring-offset-background transition-colors focus-visible:outline-dashed focus-visible:outline-2 focus-visible:outline-offset-2 disabled:pointer-events-none disabled:opacity-50 font-bold",
  {
    variants: {
      variant: {
        primary:
          "border-2 border-outline bg-brutal-surface text-brutal-surface-foreground shadow-[5px_5px_var(--outline)] transition-shadow hover:shadow-[3px_3px_var(--outline)]",
        secondary:
          "border-2 border-outline text-secondary-foreground shadow-[3px_3px_var(--outline)] transition-shadow hover:bg-secondary/80 hover:shadow-[5px_5px_var(--outline)]",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border-2 border-primary hover:border-dashed bg-transparent hover:bg-accent transition-all",
        ghost:
          "border-2 border-transparent hover:border-outline/50 hover:shadow-[3px_3px_var(--outline)]",
        link: "underline-offset-4 hover:underline focus-visible:underline decoration-dashed decoration-2 transition-shadow",
      },
      hue: {
        none: "",
        teal: "bg-teal_background-200 hover:bg-teal_background-300 border-teal_background-800 text-teal_background-800 decoration-teal_background-800 dark:bg-teal_background-800 dark:hover:bg-teal_background-700 dark:border-teal_background-200 dark:text-teal_background-100 dark:decoration-teal_background-100",
        blue: "bg-skin-400 hover:bg-skin-500 border-skin-700 text-skin-700 decoration-skin-700 dark:bg-skin-800 dark:hover:bg-skin-700 dark:border-skin-200 dark:text-skin-100 dark:decoration-skin-100",
        pink: "bg-eva_danger-500 hover:bg-eva_danger-600 border-eva_danger-800 text-eva_danger-800 decoration-eva_danger-700 dark:bg-eva_danger-800 dark:hover:bg-eva_danger-700 dark:border-eva_danger-200 dark:text-eva_danger-100 dark:decoration-eva_danger-100",
        red: "bg-blood_shot_eyes-400 hover:bg-blood_shot_eyes-500 border-blood_shot_eyes-800 text-blood_shot_eyes-800 decoration-blood_shot_eyes-600 dark:bg-blood_shot_eyes-800 dark:hover:bg-blood_shot_eyes-700 dark:border-blood_shot_eyes-200 dark:text-blood_shot_eyes-100 dark:decoration-blood_shot_eyes-100",
        yellow:
          "bg-gold-400 hover:bg-gold-500 border-gold-900 text-gold-900 decoration-gold-700 dark:bg-gold-800 dark:hover:bg-gold-700 dark:border-gold-200 dark:text-gold-100 dark:decoration-gold-100",
      },
      size: {
        default: "h-10 px-4 py-2",
        xs: "h-7 rounded-sm px-3",
        sm: "h-9 rounded-sm px-3",
        lg: "h-11 rounded-sm px-8",
        icon: "h-10 w-10",
        "icon-sm": "size-8",
        "icon-xs": "size-6",
      },
    },
    compoundVariants: [
      {
        variant: "primary",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className: "text-primary border-primary",
      },
      {
        variant: "secondary",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className: "text-primary border-primary bg-transparent",
      },
      {
        variant: "destructive",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className: "",
      },
      {
        variant: "outline",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className: "text-primary bg-transparent hover:bg-transparent",
      },
      {
        variant: "ghost",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className:
          "text-primary border-transparent bg-transparent hover:bg-transparent focus-visible:-outline-offset-2",
      },
      {
        variant: "link",
        hue: ["none", "teal", "blue", "pink", "red", "yellow"],
        className:
          "text-primary bg-transparent hover:bg-transparent focus-visible:-outline-offset-2",
      },
    ],
    defaultVariants: {
      variant: "secondary",
      hue: "none",
      size: "default",
    },
  }
)

function Button({
  className,
  variant,
  hue,
  size,
  asChild,
  children,
  ...props
}: ButtonPrimitive.Props &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  return (
    <ButtonPrimitive
      data-slot="button"
      render={asChild && React.isValidElement(children) ? children : undefined}
      className={cn(buttonVariants({ variant, hue, size, className }))}
      {...props}
    >
      {asChild ? undefined : children}
    </ButtonPrimitive>
  )
}

export { Button, buttonVariants }
export type ButtonVariant = NonNullable<
  VariantProps<typeof buttonVariants>["variant"]
>
export type ButtonHue = NonNullable<VariantProps<typeof buttonVariants>["hue"]>
export type ButtonSize = NonNullable<VariantProps<typeof buttonVariants>["size"]>

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
